async (params, browser) => {
  // Open clips page
  await browser.open(`https://www.twitch.tv/${params.channel_name}/clips?filter=clips&range=7d`)

  // Wait for clips to load
  await browser.waitForSelector('[class*=\'clip-card\'], [class*=\'ClipCard\'], article, [class*=\'tower\'] > div', 15000)

  // Let clips render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract clips
  const clips_data = await browser.evaluate(`const clips = []; const clipEls = document.querySelectorAll('[class*="clip-card"], article, [class*="tower"] > div'); for (let i = 0; i < Math.min(clipEls.length, 15); i++) { const el = clipEls[i]; const titleEl = el.querySelector('h3, [class*="title"], [data-a-target="preview-card-title-link"]'); const viewsEl = el.querySelector('[class*="views"], [class*="viewer"]'); const durationEl = el.querySelector('[class*="duration"], [class*="timestamp"]'); const creatorEl = el.querySelector('[class*="creator"], [class*="clipper"]'); const gameEl = el.querySelector('[data-a-target="preview-card-game-link"], [class*="game"]'); const linkEl = el.querySelector('a[href*="/clip/"], a'); const imgEl = el.querySelector('img'); clips.push({ title: titleEl ? titleEl.textContent.trim() : '', views: viewsEl ? viewsEl.textContent.trim() : '', duration: durationEl ? durationEl.textContent.trim() : '', creator: creatorEl ? creatorEl.textContent.trim() : '', game: gameEl ? gameEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', thumbnail: imgEl ? imgEl.getAttribute('src') : '' }); } return { channel_name: '' + params.channel_name + '', clip_count: clips.length, clips: clips, url: window.location.href }`)

  return clips_data
}
